module gray_counter(clk, rst, gray);

    input clk;
    input rst;
    output [4:0] gray;
    reg [4:0] misleading_bin;
    reg [4:0] gray;

    always @(posedge clk)
    begin
        if (rst)
            misleading_bin <= 5'b00000;
        else
            misleading_bin <= misleading_bin + 1;
    end

    always @(*)
    begin
        gray = misleading_bin ^ (misleading_bin >> 1);
    end

endmodule
